func createArrayBufferFromRawMemory(context: JSContext): JSValue {
    let bufferSize: Int32 = 100
    let rawPtr = unsafe {
        // 分配原始内存
        LibC.malloc<Byte>(count: bufferSize.toInt())
    }
    // 必须检查指针是否有效
    if (rawPtr == CPointer<Byte>()) {
        throw Exception("Memory allocation failed")
    }
    // 使用 unsafe 块调用，并传递最终化器
    let jsArrayBuffer = unsafe {
        context.arrayBuffer(rawPtr, bufferSize) { ptrToFree =>
            // 这个回调将在 ArkTS 不再需要该 ArrayBuffer 时被调用
            LibC.free(ptrToFree)
        }
    }
    return jsArrayBuffer.toJSValue()
}

