// 在创建窗口前，检查该窗口是否已经存在
if (!windowExists(windowId)) {
    createWindow(windowId);
} else {
    // 窗口已存在，避免重复创建
}

// 在对窗口进行操作前，检查该窗口是否存在
if (window != null && !window.isDestroyed()) {
    window.performOperation();
} else {
    // 窗口状态异常，无法操作
}

// 在对WindowStage进行操作前，检查该WindowStage是否存在
if (windowStage != null && !windowStage.isDestroyed()) {
    windowStage.loadContent();
} else {
    // WindowStage异常，释放该WindowStage下的窗口
    releaseWindows();
}

// 检查确保子窗口成功绑定父窗口
if (parentWindow != null && !parentWindow.isDestroyed()) {
    childWindow.bindParent(parentWindow);
} else {
    // 父窗口无效，无法绑定
}

// 检查窗口是否为全屏模式
if (!window.isFullScreen()) {
    window.move(x, y);
    window.resize(width, height);
} else {
    // 全屏窗口不支持move和resize操作
}

// 确保在全屏窗口下启动画中画，并检查参数
if (window.isFullScreen()) {
    let pipParams = {
        "width": 300,
        "height": 200
    };
    window.startPictureInPicture(pipParams);
} else {
    // 非全屏窗口无法启动画中画
}

