import kit.BasicServicesKit.*

// 获取电池电量百分比
let soc = BatteryInfo.batterySoc
// 获取充电状态
let status = BatteryInfo.chargingStatus

// 获取电池剩余电量百分比
let batteryLevel = BatteryInfo.batterySoc
print("Battery SOC: " + batteryLevel.toString())

// 检查充电状态
let chargeState = BatteryInfo.chargingStatus
if chargeState == BatteryChargeState.Enabled {
    print("Charging")
} else if chargeState == BatteryChargeState.Full {
    print("Fully charged")
}

// 获取电池健康状态
let health = BatteryInfo.healthStatus
if health == BatteryHealthState.Good {
    print("Battery health is good")
} else if health == BatteryHealthState.Overheat {
    print("Battery is overheating")
}

// 检查充电器类型
let plugType = BatteryInfo.pluggedType
if plugType == BatteryPluggedType.Usb {
    print("Charging via USB")
} else if plugType == BatteryPluggedType.Wireless {
    print("Wireless charging")
}

// 使用电量等级枚举
let capacityLevel = BatteryInfo.batteryCapacityLevel
if capacityLevel == BatteryCapacityLevel.LevelCritical {
    print("Battery level is critical!")
}

// 先检查电池是否存在
if BatteryInfo.isBatteryPresent {
    let soc = BatteryInfo.batterySoc
    print("Battery SOC: " + soc.toString())
} else {
    print("Device does not have a battery or battery is not present")
    // 可能不需要或无法获取其他电池信息
}

