// 检查参数有效性
func validateAccountParams(username: String, id: Int): Boolean {
    if (username.isEmpty() || username.length() > 1024) {
        throw new AccountException(12300002, "Invalid parameter");
    }
    if (id < 100 || id > 1099) {
        throw new AccountException(12300002, "Invalid parameter");
    }
    return true;
}

// 检查账号是否存在
func checkAccountExists(accountId: String): Boolean {
    val account = AccountManager.getAccount(accountId);
    if (account == null) {
        throw new AccountException(12300003, "The account does not exist");
    }
    return true;
}

// 创建账号前检查数量上限
func createAccountIfPossible(accountInfo: AccountInfo): Unit {
    val currentCount = AccountManager.getAccountCount();
    if (currentCount >= 1000) {
        throw new AccountException(12300007, "The number of accounts has reached the upper limit");
    }
    AccountManager.createAccount(accountInfo);
}

// 处理凭据不正确错误
func authenticateWithCredential(credential: Credential): Unit {
    try {
        AuthenticationService.authenticate(credential);
    } catch (e: AccountException) {
        if (e.code == 12300101) {
            // 提示用户凭据不正确
            showError("Credential is incorrect, please try again.");
        }
    }
}

// 处理认证锁定错误
func handleAuthenticationLock(errorCode: Int, freezingTime: Long): Unit {
    if (errorCode == 12300110) {
        // 显示锁定信息，提示用户在freezingTime后重试
        showMessage("Authentication is locked. Please retry after " + freezingTime + " milliseconds.");
    }
}

// 设置自定义数据前检查数量上限
func setCustomDataIfPossible(accountId: String, key: String, value: String): Unit {
    val currentCount = AccountManager.getCustomDataCount(accountId);
    if (currentCount >= 512) {
        throw new AccountException(12400003, "The number of custom data records reaches the upper limit");
    }
    AccountManager.setCustomData(accountId, key, value);
}

// 避免重复请求并管理认证会话
func performAccountOperation(operation: () -> Unit) {
    // 实现请求防抖或节流
    debounce(operation, 1000); // 例如，1秒内防抖
}

// 检查并管理认证会话
func startAuthSession(accountId: String): AuthSession? {
    val activeSessions = AuthenticationService.getActiveSessionCount();
    if (activeSessions >= 256) {
        throw AccountException(12300010, "The account service is busy. Too many auth sessions.");
    }
    return AuthenticationService.createSession(accountId);
}

// 验证不同账号类型的ID和用户名
func validateAccountIdentifier(accountType: String, id: Any, username: String) {
    when (accountType) {
        "SYSTEM" -> {
            val sysId = id as Int
            if (sysId <= 0 || (sysId < 100 && sysId != 0) || sysId > 1099) { // 注意：0-100为保留区间
                throw AccountException(12300002, "Invalid system account ID range.")
            }
            if (username.length > 1024) {
                throw AccountException(12300002, "System account username too long.")
            }
        }
        "DISTRIBUTED" -> {
            val distId = id as String
            if (distId.length > 512) {
                throw AccountException(12300002, "Distributed account ID too long.")
            }
            if (username.length > 256) {
                throw AccountException(12300002, "Distributed account username too long.")
            }
        }
    }
}

// 检查头像数据大小和格式
func validateAvatar(accountType: String, avatarData: ByteArray, mimeType: String) {
    val maxSize = when (accountType) {
        "SYSTEM" -> 4 * 1024 // 4KB
        "DISTRIBUTED" -> 2 * 1024 * 1024 // 2MB
        else -> throw IllegalArgumentException("Unknown account type")
    }
    if (avatarData.size > maxSize) {
        throw AccountException(12300002, "Avatar data exceeds size limit for $accountType account.")
    }
    if (mimeType !in listOf("image/jpeg", "image/png")) {
        throw AccountException(12300002, "Only JPG and PNG images are supported.")
    }
}

// 检查自定义数据键值长度
func validateCustomData(key: String, value: String) {
    if (key.length > 1024 || value.length > 1024) {
        throw AccountException(12300002, "Custom data key or value exceeds 1024 characters.")
    }
}

// 处理带超时和取消的认证
fun performAuthenticationWithTimeout(credential: Credential): AuthenticationResult {
    val timeoutMillis = 3 * 60 * 1000L // 3分钟
    val future = CompletableFuture.supplyAsync {
        AuthenticationService.authenticate(credential)
    }
    try {
        return future.get(timeoutMillis, TimeUnit.MILLISECONDS)
    } catch (e: TimeoutException) {
        future.cancel(true)
        throw AccountException(12300111, "The authentication time out.")
    } catch (e: CancellationException) {
        // 用户或系统取消了操作
        throw AccountException(12300109, "The authentication operation is canceled.")
    }
}

